import subprocess, re
repo = "/Users/jakobfaber/Developer/repos/github.com/jakobtfaber/dsa110-FLITS"

def bullets(ref):
    txt = subprocess.check_output(["git","-C",repo,"show",f"{ref}:.agents/deferred-tasks.md"], text=True)
    open_sec = txt.split("## Open",1)[1].split("## Done",1)[0]
    return {re.sub(r'\s+',' ',m.group(1).strip()) for m in re.finditer(r'^- \[[ x]\] \*\*(.+?)\*\*', open_sec, re.M)}

for ref in ["10031268","68bf9e99","HEAD"]:
    try:
        b = bullets(ref)
        print(ref, len(b), "open items")
    except Exception as e:
        print(ref, "ERR", e)

head = bullets("HEAD")
for ref,label in [("10031268","origin/main"),("68bf9e99","branch")]:
    parent = bullets(ref)
    missing = parent - head
    if missing:
        print(f"MISSING from HEAD vs {label}:", *sorted(missing), sep="\n  - ")
    else:
        print(f"All {label} open items present in HEAD")
